function autoFormatTime(v){let F=v['value']['replace'](/\D/g,'');switch(F['length']>0x4&&(F=F['slice'](0x0,0x4)),F['length']){case 0x0:case 0x1:case 0x2:v['value']=F;break;case 0x3:if(parseInt(F['slice'](0x0,0x2),0xa)<=0x17)v['value']=F['slice'](0x0,0x2)+':'+F['slice'](0x2);else{let N=F['slice'](0x0,0x1)['padStart'](0x2,'0'),V=F['slice'](0x1);v['value']=N+':'+V;}break;case 0x4:let I=F['slice'](0x0,0x2),J=F['slice'](0x2);v['value']=I+':'+J;}}function transformTimeValue(v){let F=v['trim']();if(/^\d{2}$/['test'](F))return F[0x0]['padStart'](0x2,'0')+':'+F[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](F))return 0x3===F['length']?parseInt(F['slice'](0x0,0x2),0xa)<=0x17?F['slice'](0x0,0x2)+':'+F['slice'](0x2):F['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+F['slice'](0x1):F['slice'](0x0,0x2)+':'+F['slice'](0x2);if(F['includes'](':')){let [I,J]=F['split'](':');return J||(J='00'),I=I['padStart'](0x2,'0'),J=J['padStart'](0x2,'0'),I+':'+J;}return F;}